    const job = await pool.query(
      'SELECT * FROM jobs WHERE id = $1 AND company_id = $2',
      [req.params.id, req.user.company_id]
    );

    if (job.rows.length === 0) {
      return res.status(404).json({ error: 'Job not found' });
