let editMode = false;
let editJobId = null;

document.addEventListener('DOMContentLoaded', async () => {
  const user = await checkAuth();
  if (!user) {
    window.location.href = '/login.html';
    return;
  }
  const recruiterRoles = ['employer', 'recruiter', 'hiring_manager', 'admin'];
  if (!recruiterRoles.includes(user.role)) {
    window.location.href = '/candidate-dashboard.html';
    return;
  }

  const name = user.name || user.email.split('@')[0];
  document.getElementById('user-name').textContent = name;
  document.getElementById('user-avatar').textContent = name.charAt(0).toUpperCase();
  document.getElementById('company-name').textContent = user.company_name || 'Company';

  // Check for edit mode
  const params = new URLSearchParams(window.location.search);
  const editId = params.get('edit');
  if (editId) {
    editMode = true;
    editJobId = editId;
    document.querySelector('h1').textContent = 'Edit Job Posting';
    document.querySelector('.page-header p').textContent = 'Update your job posting';
    const submitBtn = document.querySelector('button[type="submit"]');
    if (submitBtn) submitBtn.textContent = 'Save Changes';
    await loadJobForEdit(editId);
  }
});

async function loadJobForEdit(jobId) {
  try {
    const data = await apiCall(`/jobs/${jobId}`);
    if (data.job) {
      const job = data.job;
      document.getElementById('title').value = job.title || '';
      document.getElementById('location').value = job.location || '';
      document.getElementById('job_type').value = job.job_type || 'full-time';
      document.getElementById('salary_range').value = job.salary_range || '';
      document.getElementById('description').value = job.description || '';
      document.getElementById('requirements').value = job.requirements || '';
    }
  } catch (err) {
    console.error('Failed to load job for edit:', err);
    showAIResult('<div class="error-message">Failed to load job details</div>');
  }
}

